import React, { useState } from 'react';
import JobCard from '../../components/jobs/JobCard';

const JobListContainer = ({ limit, appTheme = 'dark' }) => {
    // Simulasi data (Ganti dengan fetch API Anda)
    const [jobs] = useState([
        { id: 1, title: 'Fullstack Dev', company: 'PasukanYerusSolo', location: 'Solo' },
        { id: 2, title: 'Frontend Engineer', company: 'TechEase', location: 'Jakarta' },
        { id: 3, title: 'Backend Developer', company: 'Startup Lokal', location: 'Yogyakarta' },
        { id: 4, title: 'UI/UX Designer', company: 'Creative Studio', location: 'Solo' }
    ]);

    // Jika limit ada, potong array berdasarkan limit
    const displayJobs = limit ? jobs.slice(0, limit) : jobs;

    const colors = { cardBg: '#120b06', border: '1px solid #262626', textMain: '#fef3c7' };

    return (
        <div style={{ padding: '20px 0' }}>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '20px' }}>
                {displayJobs.map(job => (
                    <div key={job.id} style={{ padding: '20px', background: colors.cardBg, border: colors.border, borderRadius: '16px' }}>
                        <h3 style={{ color: colors.textMain }}>{job.title}</h3>
                        <p style={{ color: '#a3a3a3' }}>{job.company} - {job.location}</p>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default JobListContainer;
